import{c as s,S as a,j as i,m as t}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse('{"title":"Publish a Bundle","description":"","frontmatter":{},"headers":[],"relativePath":"sharing/publish.md","filePath":"sharing/publish.md","lastUpdated":1783414742000}'),n={name:"sharing/publish.md"};function r(o,e,l,h,p,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="publish-a-bundle" tabindex="-1">Publish a Bundle <a class="header-anchor" href="#publish-a-bundle" aria-label="Permalink to “Publish a Bundle”">​</a></h1><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> publish</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drone-delivery</span></span></code></pre></div><p>One deliberate command from reviewed scope to a shareable URL:</p><ol><li><strong>The review gate runs first</strong> — the same one as <code>bundle export</code>. Anything unreviewed prints the checklist and nothing is published.</li><li>The bundle is compiled and zipped (re-using the version of your last export).</li><li>A GitHub Release is created in your configured repo via your own <code>gh</code> login, with the zip as its asset.</li><li>You get back the complete message to forward: the asset URL, its SHA-256, and <strong>who can install it</strong> — see <a href="./grant-access">Grant access</a>.</li></ol><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Published jay.drone-delivery v0.1.0 to your-org/kb-bundles (private).</span></span>
<span class="line"><span>  Who can install: members with read access to your-org/kb-bundles (private).</span></span>
<span class="line"><span>  Grant access: your-org members with base Read permission already have it;</span></span>
<span class="line"><span>                invite others at https://github.com/your-org/kb-bundles/settings/access</span></span>
<span class="line"><span>  Share:  knowlery bundle install https://github.com/.../pack.zip --verify sha256-3f7a…</span></span></code></pre></div><h2 id="first-time-setup" tabindex="-1">First-time setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to “First-time setup”">​</a></h2><p>The first publish needs a target repo — pass <code>--repo owner/name</code> (or answer the prompt). It is remembered per bundle; later publishes need nothing. If the repo doesn&#39;t exist, Knowlery offers to create it <strong>private</strong> — making a repo public is a bigger decision than publishing a release, and is left to you on GitHub.</p><p>In Obsidian, the export dialog&#39;s result screen has the same &quot;Publish to GitHub&quot; panel, sharing the same remembered configuration.</p><h2 id="publishing-publicly-the-second-gate" tabindex="-1">Publishing publicly: the second gate <a class="header-anchor" href="#publishing-publicly-the-second-gate" aria-label="Permalink to “Publishing publicly: the second gate”">​</a></h2><p>Private is always the default. <code>--public</code> states an extra fact and asks an extra question:</p><blockquote><p>A public release is permanent: caches, mirrors, and crawlers retain it even if deleted.</p></blockquote><p>If any <strong>approved</strong> item carries risk hints (emails, credentials, private IPs, person pages…), those items are re-listed and must be re-acknowledged — you approved them thinking of colleagues; the public internet is a different decision. Interactively you type <code>publish</code> to confirm; scripts and agents must pass <code>--acknowledge-risks</code>, which agents are instructed to use only after showing you the list.</p><p>The gate runs on <strong>every</strong> public publish — consenting to v1.2 does not silence v1.3&#39;s scan, because content changes and so do risks.</p><div class="warning custom-block"><p class="custom-block-title">Honest limit</p><p>Pattern scanning catches shapes (API keys, IPs, phone numbers), not meaning. It cannot know that a sentence is commercially sensitive. The per-item review — a human reading each page — remains the real gate.</p></div><h2 id="re-publishing" tabindex="-1">Re-publishing <a class="header-anchor" href="#re-publishing" aria-label="Permalink to “Re-publishing”">​</a></h2><p>The same version refuses to publish twice (<code>--force</code> replaces the asset if you must). The normal flow for changes: re-export with a bumped <code>--bundle-version</code>, then publish again — subscribers see the new version.</p><h2 id="without-gh" tabindex="-1">Without <code>gh</code> <a class="header-anchor" href="#without-gh" aria-label="Permalink to “Without gh”">​</a></h2><p>Publishing works best with GitHub&#39;s CLI (one command to install: <a href="https://cli.github.com" target="_blank" rel="noreferrer">cli.github.com</a>, then <code>gh auth login</code>). Without it, <code>publish</code> prints the complete manual path — your zip&#39;s location, the exact <code>releases/new</code> URL, the tag to use, and the SHA-256 to post — about a minute of drag-and-drop, and the result installs identically.</p>`,18)])])}const b=s(n,[["render",r]]);export{u as __pageData,b as default};
